VALUES
  ('optician-moex-01149', 'optician', 'optician-moex-109-5e38135e', 'sub-optician-01', NULL, 'single_choice', '驗光人員執業執照到期，但未依規定辦理執照更新，依驗光人員法規定，會受何種處罰？', '["廢止執業執照", "處一萬元以上，五萬元以下罰鍰，並令其限期改善", "處二萬元以上，十萬元以下罰鍰，並令其限期改善", "處三萬元以上，十五萬元以下罰鍰，並令其限期改善"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:32+00:00", "source_pdf_sha1": "384b2a4430d5", "answer_pdf_sha1": "0d51a053ccc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01150', 'optician', 'optician-moex-109-5e38135e', 'sub-optician-01', NULL, 'single_choice', '有關隱形眼鏡，下列何者錯誤？', '["驗光師可以為一般隱形眼鏡配鏡所為之驗光與配鏡", "驗光生可以為一般隱形眼鏡配鏡所為之驗光但不能配鏡", "非用於治療之隱形眼鏡，是一般隱形眼鏡", "一般隱形眼鏡之定義，須依照驗光人員法施行細則第7條之規定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:32+00:00", "source_pdf_sha1": "384b2a4430d5", "answer_pdf_sha1": "0d51a053ccc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01151', 'optician', 'optician-moex-109-5e38135e', 'sub-optician-01', NULL, 'single_choice', '依醫事人員執業登記及繼續教育辦法，有關驗光生執業其應接受之繼續教育課程積分，下列敘述何者錯 誤？', '["課程之繼續教育內容包括：專業課程、專業品質、專業倫理、專業相關法規", "課程應包括感染管制及性別議題之課程", "有規定一定年限內至少應完成之積分數", "可以抵充醫事人員受懲戒處分時所應接受之一定時數繼續教育"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:32+00:00", "source_pdf_sha1": "384b2a4430d5", "answer_pdf_sha1": "0d51a053ccc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01152', 'optician', 'optician-moex-109-5e38135e', 'sub-optician-01', NULL, 'single_choice', '有關驗光所停業或歇業時之規定，下列敘述何者錯誤？', '["應自事實發生之日起十日內，報請原發開業執照機關備查", "停業期間，以一年為限", "若停業逾一年以上者，應辦理歇業", "原發開業執照機關於其開業執照註明停業日期及理由後發還"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:32+00:00", "source_pdf_sha1": "384b2a4430d5", "answer_pdf_sha1": "0d51a053ccc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01153', 'optician', 'optician-moex-109-5e38135e', 'sub-optician-01', NULL, 'single_choice', '驗光所停業、歇業或其登記事項變更依規定應：', '["歇業不用註銷其開業登記，並無須收回開業執照", "登記事項變更無須辦理變更登記", "其所屬驗光人員無須辦理停業、歇業或變更執業處所", "停業於其開業執照註明停業日期及理由後發還"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:32+00:00", "source_pdf_sha1": "384b2a4430d5", "answer_pdf_sha1": "0d51a053ccc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 42, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01154', 'optician', 'optician-moex-109-5e38135e', 'sub-optician-01', NULL, 'single_choice', '依法規定，某負責驗光人員因故不能執行業務，導致其所屬驗光所須連續停業逾二年，下列敘述何者錯誤？', '["應填具申請書並檢附開業執照及有關文件，送由原發給開業執照機關辦理，註銷其開業登記，並收回開 業執照", "應辦理歇業", "其驗光所連續停業期間應指定合於驗光人員法規定資格者代理之，代理期間應由被代理者報請原發開業 執照機關備查", "歇業後重新申請執業登記，得以申請執業登記前一年內接受各款繼續教育課程總積分達六分之一以上之 證明文件代之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:32+00:00", "source_pdf_sha1": "384b2a4430d5", "answer_pdf_sha1": "0d51a053ccc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 43, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01155', 'optician', 'optician-moex-109-5e38135e', 'sub-optician-01', NULL, 'single_choice', '下列何者為驗光人員法中所稱低視力者輔助工具？①視障用白手杖  ②手持望遠鏡  ③手持放大鏡', '["語音手機", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:32+00:00", "source_pdf_sha1": "384b2a4430d5", "answer_pdf_sha1": "0d51a053ccc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 44, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01156', 'optician', 'optician-moex-109-5e38135e', 'sub-optician-01', NULL, 'single_choice', '醫療機構所屬驗光人員於執行業務所製作的紀錄，下列何者正確？①驗光人員不屬於醫療法範圍，執行業', '["依醫療法第67 條，屬於病歷一部分", "須至少保存七年", "未成年者之 紀錄，至少應保存至其成年後七年", "僅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:32+00:00", "source_pdf_sha1": "384b2a4430d5", "answer_pdf_sha1": "0d51a053ccc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 45, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01157', 'optician', 'optician-moex-109-5e38135e', 'sub-optician-01', NULL, 'single_choice', '有關驗光人員之執行，下列敘述何者錯誤？', '["執業不以一處為限", "可在經中央主管機關認可之機構為之", "可在所在地直轄市、縣（市）主管機關核准登記之醫療機構為之", "可在所在地直轄市、縣（市）主管機關核准登記之眼鏡公司（商號）為之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:32+00:00", "source_pdf_sha1": "384b2a4430d5", "answer_pdf_sha1": "0d51a053ccc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 46, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01158', 'optician', 'optician-moex-109-5e38135e', 'sub-optician-01', NULL, 'single_choice', '不具驗光人員資格，執行驗光業務需罰者為：', '["進行視力表量測者", "護理人員於醫師指示下為之", "於中央主管機關認可下之機構，在醫師、驗光師指導下實習之相關醫學、驗光或視光系、科學生", "相關醫學、驗光或視光系、科自取得學位日起三年內之畢業生"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:32+00:00", "source_pdf_sha1": "384b2a4430d5", "answer_pdf_sha1": "0d51a053ccc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 47, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
